entry.content:
 实现二进制拼凑某个数字

用代码表达就是从高位到低位扫描：

ll R = 0;for(int d = 29; d &gt;= 0; d--)&#123;    if(n &amp; (1ll &lt;&lt; d))&#123;  // 如果第d位是1        R = R * ten[d] + rli[d];    &#125;&#125;

这里是计算几何

使用建议

精度：定义dcmp来判断所有double
向量化
调试：cout &lt;&lt; fixed &lt;&lt; setprecision(10);



 前置头
const double EPS = 1e-9;const double PI  = acos(-1.0);inline int dcmp(double x) &#123;    if (x &lt; -EPS) return -1;    if (x &gt;  EPS) return  1;    return 0;&#125;//这个函数可以做到：1，提取数字的符号 2，比较两个数的大小:调用的时候:dcmp(a-b)inline double sqr(double x) &#123; return x * x; &#125;//取平方
 struct 点(包含重载运算符)
struct Point &#123;    double x, y;//点    Point(double x=0, double y=0):x(x),y(y)&#123;&#125;    /*    支持高效创建点    例如 Point p2(3, 4);     // (3,4)    */    Point operator+(const Point &amp;b) const &#123; return Point(x+b.x, y+b.y); &#125;    Point operator-(const Point &amp;b) const &#123; return Point(x-b.x, y-b.y); &#125;    Point operator*(double p) const &#123; return Point(x*p, y*p); &#125;    Point operator/(double p) const &#123; return Point(x/p, y/p); &#125;       /*    重载运算符，进行点的向量运算    例如: Point a(1,2), b(3,4);        Point c = a + b;  // c = (4,6)    重载乘除：对坐标进行放缩        Point v = p * 2.0;   // 坐标都 ×2        Point unit = v / v.len();  // 单位向量（后面会讲）    */    double operator^(const Point &amp;b) const &#123; return x*b.y - y*b.x; &#125; // 定义 ^ 为叉积(后面可能会用到）相当于后文的cross函数    bool operator==(const Point &amp;b) const &#123; return dcmp(x-b.x)==0 &amp;&amp; dcmp(y-b.y)==0; &#125;    /*    判断两个点在误差内是否相等（重合）    */    double len() const &#123; return hypot(x,y); &#125;               // 长度    double len2() const &#123; return x*x + y*y; &#125;               // 平方    //调用方式：double dist = (p1 - p2).len();    Point unit() const &#123; return *this / len(); &#125;            // 单位向量    Point perp() const &#123; return Point(-y, x); &#125;             // 逆时针90°    /*    调用方式：Point v(3, 4);             Point u = v.unit();  // u 是v的单位向量             Point p = v.perp();  // p = (-4, 3)    */    double dot(const Point &amp;b) const &#123; return x*b.x + y*b.y; &#125; //点积    double cross(const Point &amp;b) const &#123; return x*b.y - y*b.x; &#125; //叉积    //叉积数学公式a×b = x₁y₂ - x₂y₁ = |a||b|sinθ    double angle() const &#123; return atan2(y,x); &#125;              // 与x轴夹角    Point rotate(double theta) const &#123;         // 绕原点逆时针旋转，theta填弧度，填的是几分之几的Pi        double c=cos(theta), s=sin(theta);        return Point(x*c - y*s, x*s + y*c);    &#125;&#125;;using Vec = Point;//不要和vector撞了
 3D点struct
struct Point3 &#123;    double x, y, z; // 3D点    Point3(double x=0, double y=0, double z=0):x(x),y(y),z(z)&#123;&#125;    /*    支持高效创建点    例如 Point3 p2(3, 4, 5);     // (3,4,5)    */    Point3 operator+(const Point3 &amp;b) const &#123; return Point3(x+b.x, y+b.y, z+b.z); &#125;    Point3 operator-(const Point3 &amp;b) const &#123; return Point3(x-b.x, y-b.y, z-b.z); &#125;    Point3 operator*(double p) const &#123; return Point3(x*p, y*p, z*p); &#125;    Point3 operator/(double p) const &#123; return Point3(x/p, y/p, z/p); &#125;        /*    重载运算符，进行点的向量运算    例如: Point3 a(1,2,3), b(4,5,6);          Point3 c = a + b;  // c = (5,7,9)    重载乘除：对坐标进行放缩          Point3 v = p * 2.0;   // 坐标都 ×2          Point3 unit = v / v.len();  // 单位向量    */    // 定义 ^ 为叉积。注意：3D叉积返回的是一个【向量】，而不是2D里的标量！    Point3 operator^(const Point3 &amp;b) const &#123;         return Point3(y*b.z - z*b.y, z*b.x - x*b.z, x*b.y - y*b.x);     &#125;     bool operator==(const Point3 &amp;b) const &#123;         return dcmp(x-b.x)==0 &amp;&amp; dcmp(y-b.y)==0 &amp;&amp; dcmp(z-b.z)==0;     &#125;    /*    判断两个点在误差内是否相等（重合）    */    // 长度。注：C++17 开始支持 std::hypot(x,y,z)，如果编译器较老建议用 sqrt    double len() const &#123; return sqrt(x*x + y*y + z*z); &#125;                   double len2() const &#123; return x*x + y*y + z*z; &#125;                 // 平方    //调用方式：double dist = (p1 - p2).len();    Point3 unit() const &#123; return *this / len(); &#125;                   // 单位向量        // 注意：3D中没有单一的 perp() (逆时针90°)，因为垂直于一条线的向量有无数个    // 注意：3D中也没有单一的 angle() (与x轴夹角)，通常需要用点积求两个向量之间的夹角    double dot(const Point3 &amp;b) const &#123; return x*b.x + y*b.y + z*b.z; &#125; // 点积    Point3 cross(const Point3 &amp;b) const &#123; return *this ^ b; &#125;           // 叉积    /*    3D叉积数学公式 a×b = (y₁z₂ - z₁y₂, z₁x₂ - x₁z₂, x₁y₂ - y₁x₂)    几何意义：生成一个垂直于a和b所在平面的法向量。    该向量的长度 |a×b| = |a||b|sinθ，即两向量构成的平行四边形面积。    */    /*    3D 旋转：罗德里格斯旋转公式 (Rodrigues&#x27; rotation formula)    参数：axis 为旋转轴（必须是单位向量），theta 为旋转角度（弧度）    调用方式：Point3 v_new = v.rotate(Point3(0,0,1), PI/2); // 绕Z轴转90度    */    Point3 rotate(const Point3 &amp;axis, double theta) const &#123;        double c = cos(theta), s = sin(theta);        Point3 v = *this;        // 公式：v&#x27; = v*cosθ + (axis×v)*sinθ + axis*(axis·v)*(1-cosθ)        return v * c + axis.cross(v) * s + axis * (axis.dot(v)) * (1 - c);    &#125;&#125;;using Vec3 = Point3; // 不要和vector撞了
 常用函数
// 向量叉积 (a×b)double Cross(Point a, Point b) &#123; return a.x*b.y - a.y*b.x; &#125;// 向量点积double Dot(Point a, Point b) &#123; return a.x*b.x + a.y*b.y; &#125;// 两点距离double Dist(Point a, Point b) &#123; return (a-b).len(); &#125;//需要重载.len()// 点到直线距离 (p 到 ab)double DistToLine(Point p, Point a, Point b) &#123;    return fabs(Cross(p-a, b-a)) / Dist(a,b);&#125;//两点之间距离（简单版）double disPointPoint(Point u,Point v)&#123;    return sqrt((u.x-v.x)*(u.x-v.x)+(u.y-v.y)*(u.y-v.y));&#125;// 点到线段距离double DistToSeg(Point p, Point a, Point b) &#123;    if (a==b) return Dist(p,a);    Vec v1 = b-a, v2 = p-a, v3 = p-b;    if (dcmp(Dot(v1,v2)) &lt; 0) return Dist(p,a);    if (dcmp(Dot(v1,v3)) &gt; 0) return Dist(p,b);    return DistToLine(p,a,b);&#125;// 点 p 在线段 ab 上的投影Point Proj(Point p, Point a, Point b) &#123;    Vec v = b-a;    return a + v * (Dot(v, p-a) / v.len2());&#125;// 判两线段AB和CD是否相交（含端点）bool SegIntersect(Point a,Point b,Point c,Point d) &#123;    auto ccw = [](Point p,Point q,Point r)    &#123; return dcmp(Cross(q-p, r-p)); &#125;;//作用：判断点 r 在直线 pq 的哪一侧    return ccw(a,b,c)*ccw(a,b,d)&lt;=0 &amp;&amp; ccw(c,d,a)*ccw(c,d,b)&lt;=0;&#125;/*原理：两条线段相交的充要条件：C 和 D 在 AB 的两侧或线上A 和 B 在 CD 的两侧或线上*/// 判断点 p 是否在 线段 ab 上（包括端点 a 和 b）bool OnSeg(Point p, Point a, Point b) &#123;    return dcmp(Cross(p-a,b-a))==0 &amp;&amp; dcmp(Dot(p-a,p-b))&lt;=0;&#125;

共线：Cross(p-a, b-a) = (p-a) × (b-a)
在点区间内：Dot(p-a, p-b) &lt;= 0

 3D常用函数
// 假设之前已经定义了 Point3, Vec3 和 dcmp，且 ^ 重载为了叉积/* 1. 点到直线的距离原理：叉积的模长等于平行四边形面积，面积除以底边长等于高。参数：点 p，直线上的两点 a 和 b*/double distToLine(Point3 p, Point3 a, Point3 b) &#123;    Vec3 v1 = b - a;    Vec3 v2 = p - a;    return (v1 ^ v2).len() / v1.len(); &#125;/*2. 点到线段的距离原理：先利用点积判断垂足是否在线段上，如果在外面则退化为点到端点的距离。参数：点 p，线段的两个端点 a 和 b*/double distToSegment(Point3 p, Point3 a, Point3 b) &#123;    if (a == b) return (p - a).len();    Vec3 v1 = b - a, v2 = p - a, v3 = p - b;        if (dcmp(v1.dot(v2)) &lt; 0) return v2.len();      // 垂足在 a 的外侧，离 a 更近    if (dcmp(v1.dot(v3)) &gt; 0) return v3.len();      // 垂足在 b 的外侧，离 b 更近    return (v1 ^ v2).len() / v1.len();              // 垂足在线段上，同点到直线的距离&#125;/*3. 点在直线上的投影点 (求垂足)原理：利用点积求出投影长度的比例，再用向量加法从起点推过去。参数：点 p，直线上的两点 a 和 b*/Point3 projectionOnLine(Point3 p, Point3 a, Point3 b) &#123;    Vec3 v = b - a;    // (p-a).dot(v) 是投影长度乘以 v 的长度。再除以 v.len2() 就得到了 t 的比例    double t = (p - a).dot(v) / v.len2();     return a + v * t;&#125;/*4. 求平面的单位法向量原理：在平面上任取三个不共线的点，两两连成向量做叉积，然后归一化。参数：平面上三个不共线的点 p1, p2, p3*/Vec3 getNormal(Point3 p1, Point3 p2, Point3 p3) &#123;    return ((p2 - p1) ^ (p3 - p1)).unit();&#125;/*5. 点到平面的距离原理：把点和平面上的已知点连成向量，求它在法向量上的投影长度（点积的绝对值）。参数：点 p，平面上任意一点 p0，平面的单位法向量 n注意：传进来的 n 必须是单位向量 (unit)*/double distToPlane(Point3 p, Point3 p0, Vec3 n) &#123;    return fabs((p - p0).dot(n));&#125;/*6. 点在平面上的投影点原理：点 p 沿着法向量的反方向移动“点到平面的带符号距离”，就能落在平面上。参数：点 p，平面上任意一点 p0，平面的单位法向量 n注意：传进来的 n 必须是单位向量 (unit)*/Point3 projectionOnPlane(Point3 p, Point3 p0, Vec3 n) &#123;    double d = (p - p0).dot(n); // 注意这里不加绝对值，保留正负号来指示方向    return p - n * d;           &#125;/*7. 判断四点共面原理：三个点构成平面（求出法向量），看第四个点到这个平面的距离是否为 0。参数：四个点 a, b, c, d*/bool isCoplanar(Point3 a, Point3 b, Point3 c, Point3 d) &#123;    Vec3 n = (b - a) ^ (c - a); // 不需要 unit，只要判断点积是否为 0 即可    return dcmp((d - a).dot(n)) == 0;&#125;
 排序(大部分时间我手搓lambda，这是属于提醒自己)
//以x升序排列，其次以y升序排列bool sortXupYup(Point u,Point v)&#123; if(u.x!=v.x) return u.x&lt;v.x; else return u.y&lt;v.y;&#125;//以y升序排列，其次以x升序排列bool sortYupXup(Point u,Point v)&#123; if(u.y!=v.y) return u.y&lt;v.y; else return u.x&lt;v.x;&#125;//对点进行极角排序bool sortPointAngle(Point a,Point b)&#123; if(a.quad()!=b.quad()) return a.quad()&lt;b.quad(); return (a^b)&gt;0;&#125;
 几何公式
//余弦定理 ab为邻边，c为对边double cosLaw(double a,double b,double c)&#123;    return (a*a+b*b-c*c)/(2*a*b);&#125;//三角形面积叉积法double mianj(Point u,Point v,Point w)&#123;    return abs((v-u)^(w-u))/2.0;&#125;//求多边形面积（只能求凸包）double polygonArea(Point *u,int size)&#123;    double area=0;    Point begin=u[1]; /*   由第一个点起始的顺序叉积，   面积值为边之间连线的封闭部分，叉积能够计算容斥部分  */    for(int i=3;i&lt;=size;i++) area+=((u[i-1]-begin)^(u[i]-begin))/2;    return area;&#125;// 适用于任意简单多边形的计算面积公式，注意顶点要按照顺序给出double polygonArea2(Point *u, int size)&#123;    if (size &lt; 3) return 0.0; // 点/线没有面积    double area = 0;    u[size+1] = u[1]; // 哨兵，使循环闭合    for (int i = 1; i &lt;= size; i++) &#123;        // 假设你已经重载了 ^        // area += (u[i] ^ u[i+1]);        area += u[i].cross(u[i+1]);    &#125;    return fabs(area / 2.0);&#125;
 正多边形&amp;&amp;圆
// 正 n 边形外接圆半径 R → 边长double RegSide(double R, int n) &#123; return 2 * R * sin(PI / n); &#125;// 正 n 边形内接圆半径 r → 边长double RegSideIn(double r, int n) &#123; return 2 * r * tan(PI / n); &#125;// 用于生成一个正多边形的顶点坐标。(中心 O，半径 R，起始角度 theta0)vector&lt;Point&gt; RegularPoly(Point O, double R, int n, double theta0 = 0) &#123;    vector&lt;Point&gt; res;    double ang = 2*PI/n;    for (int i = 0; i &lt; n; ++i) &#123;        double a = theta0 + i*ang;        res.emplace_back(O.x + R*cos(a), O.y + R*sin(a));    &#125;    return res;&#125;
// 圆的面积 – 两点 + 半径 构造圆struct Circle &#123;    Point c;//圆心    double r;//半径    Circle(Point c=Point(), double r=0):c(c),r(r)&#123;&#125;    //调用：Circle cir(Point(1, 1), 5.0);  // 圆心 (1,1)，半径 5    // 三点确定圆 (非共线)    //调用：Circle cir1(A, B, C);    Circle(Point a, Point b, Point c) &#123;        Point ab = (a+b)*0.5, bc = (b+c)*0.5;        Vector d1 = (b-a).perp(), d2 = (c-b).perp();        Point o = LineIntersect(ab, ab+d1, bc, bc+d2);        *this = Circle(o, Dist(o,a));    &#125;&#125;;


三点定圆需要定义LineIntersect函数（详见后面）


生成正多边形顶点坐标几何原理：
使用极坐标转直角坐标公式：


x=Ox+R⋅cos⁡(θ),y=Oy+R⋅sin⁡(θ)x = O_x + R \cdot \cos(\theta), \quad y = O_y + R \cdot \sin(\theta)
x=Ox​+R⋅cos(θ),y=Oy​+R⋅sin(θ)
从 theta0 开始，每次旋转 2π/n 弧度，生成一个顶点。

用法示例

Point center = &#123;0, 0&#125;;
auto pentagon = RegularPoly(center, 1.0, 5, 0);  // 正五边形，半径1，顶点从x轴正方向开始
会生成 5 个点，均匀分布在单位圆上。



 直线&amp;线段交点

需要Point重载±*;需要using Vec = Point; 需要点积叉积;
判断p是否在AB上;需要标准线段相交判断(不一定)

// 直线参数方程交点Point LineIntersect(Point p1, Vec v1, Point p2, Vec v2) &#123;    double t = Cross(p2-p1, v2) / Cross(v1, v2);    return p1 + v1 * t;&#125;// 两线段交点（若相交返回 true，交点写入 its）bool SegIntersection(Point a, Point b, Point c, Point d, Point &amp;its) &#123;    if (!SegIntersect(a,b,c,d)) return false;    double t = Cross(c-a, d-c) / Cross(b-a, d-c);    its = Point(a.x + t*(b.x-a.x), a.y + t*(b.y-a.y));    return true;&#125;

求线段交点核心代码片段:double t = Cross(c-a, d-c) / Cross(b-a, d-c);
its = Point(a.x + t*(b.x-a.x), a.y + t*(b.y-a.y));

 凸包：我不会
int ConvexHull(vector&lt;Point&gt; &amp;p, vector&lt;Point&gt; &amp;hull) &#123;    int n = p.size(); if (n&lt;=1) &#123; hull=p; return n; &#125;    sort(p.begin(), p.end(), [](Point a, Point b)&#123;        return dcmp(a.x-b.x)&lt;0 || (dcmp(a.x-b.x)==0 &amp;&amp; dcmp(a.y-b.y)&lt;0);    &#125;);    hull.clear(); hull.reserve(n);    // 下凸包    for (int i=0;i&lt;n;i++)&#123;        while (hull.size()&gt;=2 &amp;&amp; dcmp(Cross(hull.back()-hull[hull.size()-2], p[i]-hull.back())) &lt;=0)            hull.pop_back();        hull.push_back(p[i]);    &#125;    int t = hull.size();    // 上凸包    for (int i=n-2;i&gt;=0;i--)&#123;        while (hull.size()&gt;t &amp;&amp; dcmp(Cross(hull.back()-hull[hull.size()-2], p[i]-hull.back())) &lt;=0)            hull.pop_back();        hull.push_back(p[i]);    &#125;    hull.pop_back(); // 去掉重复起点    return hull.size();&#125;
 旋转卡壳 – 直径、对踝(我不会)
// 凸多边形直径（最远点对）double Diameter(const vector&lt;Point&gt; &amp;hull) &#123;    int n = hull.size(); if (n&lt;=1) return 0;    if (n==2) return Dist(hull[0],hull[1]);    int i=0,j=1;    for (int k=0;k&lt;n;k++)        if (dcmp(hull[k].x - hull[i].x)&gt;0) i=k;    j = (i+1)%n;    int si=i,sj=j;    double res = 0;    while (i!=sj || j!=si)&#123;        res = max(res, Dist(hull[i],hull[j]));        if (dcmp(Cross(hull[(i+1)%n]-hull[i], hull[(j+1)%n]-hull[j])) &lt; 0) i=(i+1)%n;        else j=(j+1)%n;    &#125;    return res;&#125;
 最小圆覆盖 O(n)
Circle MinCircleCover(vector&lt;Point&gt; p) &#123;    random_shuffle(p.begin(), p.end());    int n = p.size();    Circle c(p[0], 0);    for (int i=1;i&lt;n;i++) if (dcmp(Dist(c.c, p[i]) - c.r) &gt; 0) &#123;        c = Circle(p[i],0);        for (int j=0;j&lt;i;j++) if (dcmp(Dist(c.c, p[j]) - c.r) &gt; 0) &#123;            c = Circle((p[i]+p[j])*0.5, Dist(p[i],p[j])*0.5);            for (int k=0;k&lt;j;k++) if (dcmp(Dist(c.c, p[k]) - c.r) &gt; 0) &#123;                c = Circle(p[i], p[j], p[k]);            &#125;        &#125;    &#125;    return c;&#125;
 半平面交 O(n log n)
struct Halfplane &#123;    Point p; Vector v; double ang;    Halfplane()&#123;&#125;    Halfplane(Point a, Point b)&#123; p=a; v=b-a; ang=atan2(v.y,v.x); &#125;    bool operator&lt;(const Halfplane &amp;b) const &#123; return ang &lt; b.ang; &#125;    Point intersect(const Halfplane &amp;b) const &#123;        double t = Cross(b.p-p, b.v) / Cross(v, b.v);        return p + v*t;    &#125;&#125;;vector&lt;Point&gt; HalfplaneIntersect(vector&lt;Halfplane&gt; hp) &#123;    sort(hp.begin(), hp.end());    int n = hp.size(), l=0, r=0;    vector&lt;Halfplane&gt; q(n+5);    vector&lt;Point&gt; res;    q[r++] = hp[0];    for (int i=1;i&lt;n;i++)&#123;        while (l+1 &lt; r &amp;&amp; dcmp(Cross(hp[i].p - q[r-2].intersect(q[r-1]), hp[i].v)) &lt; 0) --r;        while (l &lt; r &amp;&amp; dcmp(Cross(hp[i].p - q[l].intersect(q[l+1]), hp[i].v)) &lt; 0) ++l;        q[r++] = hp[i];    &#125;    while (l+1 &lt; r &amp;&amp; dcmp(Cross(q[l].p - q[r-2].intersect(q[r-1]), q[l].v)) &lt; 0) --r;    while (l &lt; r &amp;&amp; dcmp(Cross(q[r-1].p - q[l].intersect(q[l+1]), q[r-1].v)) &lt; 0) ++l;    if (r-l&lt;=1) return res;    for (int i=l;i&lt;r;i++) res.push_back(q[i].intersect(q[(i+1==r)?l:i+1]));    return res;&#125;
 分治
来自知乎复制粘贴链接
感谢大佬整理
//分治void Nearestpoint(point *a,int l,int r,int &amp;u,int &amp;v,double &amp;d)&#123; /*   应当注意距离的定义形式，如果为平方的形式，   则代码中绝对值的部分也应当改为平方  */ if(l==r) return ; if(l+1==r) &#123;  if(disPointPoint(a[l],a[r])&lt;d) d=disPointPoint(a[l],a[r]),u=l,v=r;  return ; &#125; int mid=l+r&gt;&gt;1,m=0; Nearestpoint(a,l,mid,u,v,d),Nearestpoint(a,mid+1,r,u,v,d); point b[r-l+10]; for(int i=l;i&lt;=r;i++)&#123;  if(abs(a[i].x-a[mid].x)&lt;d) b[++m]=a[i]; &#125; sort(b+1,b+1+m,sortYupXup); for(int i=1;i&lt;=m;i++)&#123;  for(int j=i+1;j&lt;=m&amp;&amp;abs(b[i].y-b[j].y)&lt;d;j++)&#123;   if(d&gt;disPointPoint(b[i],b[j]))d=disPointPoint(b[i],b[j]),u=i,v=j;  &#125; &#125; return ;&#125;//分治法的入口,分治前需要排序double mindisset1(point* a,int size,int &amp;u,int &amp;v)&#123; //函数起始入口 double minn=1e18; sort(a+1,a+1+size,sortXupYup); Nearestpoint(a,1,size,u,v,minn); return minn;&#125;//multisetdouble mindisset2(point* u,int size)&#123; double ans=1e20; struct cmp_y &#123;  bool operator()(const point &amp;a, const point &amp;b) const &#123; return a.y &lt; b.y; &#125; &#125;; multiset&lt;point,cmp_y&gt;s; for (int i = 1, l = 1; i &lt;=size; i++) &#123;  while (l &lt; i &amp;&amp; u[i].x - u[l].x &gt;= ans) s.erase(s.find(u[l++]));  for (auto it = s.lower_bound(point&#123;u[i].x, u[i].y - ans&#125;);   it != s.end() &amp;&amp; it-&gt;y - u[i].y &lt; ans; it++)&#123;   if(disPointPoint(*it,u[i])&lt;ans) ans=disPointPoint(*it,u[i]);  &#125;  s.insert(u[i]); &#125; return ans;&#125;

