#include &lt;iostream&gt;#include &lt;vector&gt;#include &lt;numeric&gt; // 用于 std::gcd (C++17), 但手写gcd更通用using namespace std;// ================= 配置区域 =================const int MAXN = 1000005; // 筛的范围，根据题目要求修改 (通常 1e6 到 1e7)// ===========================================// --- 变量定义 ---// primes: 用来存所有的质数// min_prime: min_prime[i] 表示数字 i 的最小质因子 (可选，用于快速分解质因数)// phi: 欧拉函数 phi[i] 表示 1...i 中与 i 互质的数的个数// is_prime: 标记数组，true 表示是质数，false 表示是合数 (或者是 bool not_prime)vector&lt;int&gt; primes; int min_prime[MAXN]; int phi[MAXN];       bool is_not_prime[MAXN]; // 为了防止 bool 初始化陷阱，通常用 &quot;is_not_prime&quot; (默认为false，即默认都是质数)// ==========================================================// 核心模块 1: 欧拉筛 (Linear Sieve)// 时间复杂度: O(N) - 绝对线性，不随数据波动// ==========================================================void euler_sieve(int n) &#123;    // 1. 初始化    // 0 和 1 既不是质数也不是合数，但在代码逻辑中要把它们标记掉    is_not_prime[0] = is_not_prime[1] = true;    phi[1] = 1; // 1 的欧拉函数特例为 1    // 2. 开始遍历每一个数    for (int i = 2; i &lt;= n; i++) &#123;        // 如果当前数没有被标记过，说明它是质数        if (!is_not_prime[i]) &#123;            primes.push_back(i); // 把它加入质数列表            phi[i] = i - 1;      // 质数 p 的欧拉函数是 p-1            min_prime[i] = i;    // 质数的最小质因子是它自己        &#125;        // 3. 用当前已有的质数去筛掉合数        // j 是 primes 数组的下标，primes[j] 是当前的质数        for (int j = 0; j &lt; primes.size(); j++) &#123;            // 计算要筛掉的合数：当前数 i * 质数 primes[j]            // 如果乘积超过了范围，直接停止            if (i * primes[j] &gt; n) break;            // 标记这个合数            int composite_num = i * primes[j];            is_not_prime[composite_num] = true;            min_prime[composite_num] = primes[j]; // 记录它的最小质因子            // === [核心逻辑] 欧拉筛的灵魂 ===            // 如果 i 能够被当前的质数 primes[j] 整除            // 说明 i 已经被 primes[j] 筛过了（或者包含这个因子）            // 那么 i * primes[j+1] 这个合数，应该由 primes[j] 后面更大的质数来筛吗？            // 不！为了保证线性复杂度，每个数只能被它&quot;最小&quot;的质因子筛掉。            // 因为 primes[j] 是 i 的因子，所以 primes[j] 也一定是 (i * primes[j+1]) 的最小因子。            // 如果我们不 break，继续用更大的质数筛，就会导致重复筛选，退化成 O(N log log N)。            if (i % primes[j] == 0) &#123;                // 此时更新积性函数 phi 的公式 (特殊情况)                phi[composite_num] = phi[i] * primes[j];                break; // 必须立刻跳出循环！            &#125; else &#123;                // 如果 i 不能被 primes[j] 整除 (互质情况)                // phi 的积性性质: phi(a * b) = phi(a) * phi(b)                phi[composite_num] = phi[i] * (primes[j] - 1);            &#125;        &#125;    &#125;&#125;// ==========================================================// 核心模块 2: 最大公约数 (GCD) &amp; 最小公倍数 (LCM)// 时间复杂度: O(log(min(a, b)))// ==========================================================// 递归写法 (推荐，现代编译器优化后极快)long long gcd(long long a, long long b) &#123;    return b == 0 ? a : gcd(b, a % b);&#125;// 最小公倍数 = (a * b) / gcd(a, b)// 注意：先除后乘，防止 a * b 直接溢出 long longlong long lcm(long long a, long long b) &#123;    if (a == 0 || b == 0) return 0;    return (a / gcd(a, b)) * b;&#125;int main() &#123;    // 优化 I/O    ios::sync_with_stdio(0); cin.tie(0);    // 1. 必须先调用筛法预处理    // 假设题目范围是 1000    euler_sieve(1000);     // --- 用法演示 ---        // 1. 判断是否为质数 O(1)    int x = 997;    if (!is_not_prime[x]) &#123;        cout &lt;&lt; x &lt;&lt; &quot; is a prime number.&quot; &lt;&lt; endl;    &#125;    // 2. 输出前 10 个质数    cout &lt;&lt; &quot;Top 10 primes: &quot;;    for(int i = 0; i &lt; 10 &amp;&amp; i &lt; primes.size(); i++) &#123;        cout &lt;&lt; primes[i] &lt;&lt; &quot; &quot;;    &#125;    cout &lt;&lt; endl;    // 3. 查询欧拉函数 (比 x 小且与 x 互质的数的个数)    // 比如 phi(8) = 4 (即 1, 3, 5, 7)    cout &lt;&lt; &quot;phi(8) = &quot; &lt;&lt; phi[8] &lt;&lt; endl;    // 4. GCD / LCM    cout &lt;&lt; &quot;GCD(24, 36) = &quot; &lt;&lt; gcd(24, 36) &lt;&lt; endl;    cout &lt;&lt; &quot;LCM(24, 36) = &quot; &lt;&lt; lcm(24, 36) &lt;&lt; endl;    return 0;&#125;
#include &lt;iostream&gt;using namespace std;// ==========================================// 1. 配置区域// ==========================================using ll = long long; // 使用 long long 防止运算溢出const int MOD = 1e9 + 7; // 题目通常给定的模数 (必须是质数)// ==========================================// 2. 核心算法模版// ==========================================// 函数：快速幂 (Binary Exponentiation)// 作用：快速计算 (base^exp) % MOD// 复杂度：O(log exp)ll qpow(ll base, ll exp) &#123;    ll res = 1;    while (exp &gt; 0) &#123;        // 如果指数是奇数，乘上底数        if (exp &amp; 1) res = res * base % MOD;        // 底数翻倍，指数减半        base = base * base % MOD;        exp &gt;&gt;= 1;    &#125;    return res;&#125;// 函数：求乘法逆元 (Modular Inverse)// 作用：求 n 在模 MOD 下的逆元 (相当于求 1/n)// 原理：费马小定理 -&gt; n^(MOD-2)// 限制：MOD 必须是质数ll inv(ll n) &#123;    return qpow(n, MOD - 2);&#125;// ==========================================// 3. 实际使用演示// ==========================================// 封装一个安全的除法函数 (可选，方便调用)// 计算 (a / b) % MODll div_mod(ll a, ll b) &#123;    // 核心步骤：    // 1. 算出 b 的逆元 (inv_b)    // 2. 这里的 a 可能是非常大的数，也可以是已经取模过的数    // 3. 结果 = a * inv_b % MOD    return (a % MOD) * inv(b) % MOD;&#125;int main() &#123;    // 优化输入输出速度    ios::sync_with_stdio(0); cin.tie(0);    // --- 场景一：基础验证 ---    // 我们知道 10 / 2 = 5    ll a = 10;    ll b = 2;        cout &lt;&lt; &quot;场景一 (10/2):&quot; &lt;&lt; endl;    // 调用逆元逻辑    // 步骤 A: 算出 b(2) 的逆元    ll b_inverse = inv(b);     // 步骤 B: 计算 a * 逆元    ll res = a * b_inverse % MOD;         cout &lt;&lt; &quot;10 / 2 (mod 1e9+7) = &quot; &lt;&lt; res &lt;&lt; endl; // 输出 5    cout &lt;&lt; &quot;---------------------------&quot; &lt;&lt; endl;    // --- 场景二：ACM 常见的大数除法 ---    // 假设题目要求计算: (10^18) / 5  % (1e9+7)    // 注意：这里的 10^18 已经大到 long long 存不下了，    // 通常 a 是在之前的步骤里通过不断取模算出来的。        cout &lt;&lt; &quot;场景二 (大数除法):&quot; &lt;&lt; endl;        // 模拟 a 非常大的情况，假设 a 经过之前的计算已经是取模后的结果了    // 假设真实的 A = 1000000000000000005 (很大)    // 我们手头只有 A % MOD 的值    ll huge_A = 1000000000000000005LL;     ll A_mod = huge_A % MOD; // 此时 A_mod 只是一个较小的数    ll B = 5;    // 错误演示：直接除    // cout &lt;&lt; A_mod / B &lt;&lt; endl; // 绝对错误！取模后的数变小了，不能直接除 B    // 正确演示：乘逆元    // 这一步本质是： (A * (1/B)) % MOD    ll ans = A_mod * inv(B) % MOD;    cout &lt;&lt; &quot;结果: &quot; &lt;&lt; ans &lt;&lt; endl;    // 验证一下：    // 真实结果应该是 huge_A / 5 = 200000000000000001    // 我们看看 200000000000000001 % MOD 是多少    cout &lt;&lt; &quot;验证: &quot; &lt;&lt; (huge_A / B) % MOD &lt;&lt; endl;        return 0;&#125;
