// ==========================================// 1. 万能头与加速 (必写!)// ==========================================#include &lt;bits/stdc++.h&gt; using namespace std;int main() &#123;    // 关流加速 (防止 cin/cout 超时)    ios::sync_with_stdio(0);     cin.tie(0); cout.tie(0);     // ==========================================    // 2. vector (动态数组) - 真的很常用    // ==========================================    vector&lt;int&gt; v;    v.push_back(1);      // 尾部插入    v.pop_back();        // 尾部删除    v.size();            // 获取长度    v.clear();           // 清空    v.empty();           // 判空 (true为空)        // 排序 (默认从小到大)    sort(v.begin(), v.end());     // 去重 (必须先排序!)    v.erase(unique(v.begin(), v.end()), v.end());     // ==========================================    // 3. string (字符串) - 别再看成子序列了!    // ==========================================    string s = &quot;abcdef&quot;;    // 截取: s.substr(开始下标, 长度)    string sub = s.substr(1, 3); // &quot;bcd&quot;        // 查找: s.find(&quot;子串&quot;) -&gt; 返回下标，找不到返回 string::npos    if (s.find(&quot;cd&quot;) != string::npos) &#123;         // 找到了    &#125;        // 字典序比较: 直接用 &gt; &lt; ==    string s1 = &quot;apple&quot;, s2 = &quot;banana&quot;;    if (s1 &lt; s2) &#123;&#125; // true    // ==========================================    // 4. sort 与 自定义比较 (结构体排序必备)    // ==========================================    struct Node &#123; int x, y; &#125;;    vector&lt;Node&gt; a;        // 规则: x 从小到大排; 如果 x 一样，y 从大到小排    sort(a.begin(), a.end(), [&amp;](Node n1, Node n2) &#123;        if (n1.x != n2.x) return n1.x &lt; n2.x;         return n1.y &gt; n2.y;     &#125;);    // ==========================================    // 5. 二分查找 (神器! 必须背! 数组必须有序!)    // ==========================================    vector&lt;int&gt; nums = &#123;1, 3, 5, 7, 9&#125;;    // lower_bound: 第一个 &gt;= k 的位置    // upper_bound: 第一个 &gt; k 的位置    int k = 5;    int pos1 = lower_bound(nums.begin(), nums.end(), k) - nums.begin(); // 返回下标    int pos2 = upper_bound(nums.begin(), nums.end(), k) - nums.begin();         // 如果找不到，返回值等于 nums.size()    // ==========================================    // 6. map (键值对) &amp; set (自动排序去重)    // ==========================================    map&lt;string, int&gt; mp;    mp[&quot;apple&quot;] = 1;    // 查找键是否存在    if (mp.count(&quot;apple&quot;)) &#123;&#125; // 1存在, 0不存在    // 遍历 map    for (auto p : mp) &#123;        // p.first 是 key, p.second 是 value    &#125;    set&lt;int&gt; st; // 自动从小到大排序，不重复    st.insert(5);    st.erase(5);    // set 的二分查找要用自带的，否则慢死    auto it = st.lower_bound(3);     // ==========================================    // 7. priority_queue (优先队列 - 贪心/Dijkstra用)    // ==========================================    // 默认是大根堆 (最大的在 top)    priority_queue&lt;int&gt; pq;     // 小根堆 (最小的在 top) - 常用!    priority_queue&lt;int, vector&lt;int&gt;, greater&lt;int&gt;&gt; min_pq;         pq.push(10);    int top = pq.top(); // 取队头    pq.pop(); // 删队头    // ==========================================    // 8. 数学常用小工具    // ==========================================    // 最大公约数 GCD    int g = __gcd(12, 18);     // 最小公倍数 LCM = (a*b) / gcd(a,b)        // 绝对值    int x = abs(-5);        // 交换    swap(x, g);        // max/min 找最大最小    int mx = max(1, 2);    int mn = min(&#123;1, 2, 3, 4&#125;); // 多个数要加 &#123;&#125;    // 赋值 (慎用 memset 除非初始化为 0 或 -1)    int arr[100];    memset(arr, 0, sizeof(arr)); // 全部清零    memset(arr, -1, sizeof(arr)); // 全部设为 -1    // 如果要设为极大值 (0x3f3f3f3f 约为 1e9)    memset(arr, 0x3f, sizeof(arr));         // 全排列 (暴力破解用)    vector&lt;int&gt; p = &#123;1, 2, 3&#125;;    do &#123;        // 这里处理每一种排列    &#125; while (next_permutation(p.begin(), p.end()));    return 0;&#125;
 字符串
#include &lt;bits/stdc++.h&gt;using namespace std;int main() &#123;    // ==========================================    // 1. 读入带空格的字符串 (整行读入)    // ==========================================    string s;    // cin &gt;&gt; s;         // 遇到空格就停止，不能读句子    getline(cin, s);     // 读入一整行 (包括空格)!     // 注意: 如果前面用了 cin &gt;&gt; n，记得先用 cin.ignore() 吃掉换行符再 getline    // ==========================================    // 2. 截取子串 (Substr) - 最常用的功能    // ==========================================    // s.substr(开始下标, 截取长度)     // 注意: 第二个参数是长度，不是结束下标！    string sub = s.substr(2, 3); // 从下标2开始，截取3个字符    // ==========================================    // 3. 查找 (Find)    // ==========================================    string t = &quot;abc&quot;;    int pos = s.find(t); // 查找 t 在 s 中第一次出现的位置        // 必须判断是否找到！    if (pos != string::npos) &#123;        // 找到了，pos 是下标    &#125; else &#123;        // 没找到    &#125;        // rfind(): 从右往左找 (找最后一个出现的位置)    int last_pos = s.rfind(t);    // ==========================================    // 4. 数字 &lt;--&gt; 字符串 互转 (神器!)    // ==========================================    // A. 字符串 转 数字    string num_str = &quot;12345&quot;;    int n = stoi(num_str);       // 转 int    long long ll = stoll(num_str); // 转 long long (防爆int)        // B. 数字 转 字符串    int x = 996;    string x_str = to_string(x); // 变成 &quot;996&quot;    // ==========================================    // 5. 反转字符串 (判断回文必备)    // ==========================================    string s2 = &quot;hello&quot;;    reverse(s2.begin(), s2.end()); // s2 变成了 &quot;olleh&quot;        // 判断回文常用套路:    string temp = s;    reverse(temp.begin(), temp.end());    if (s == temp) &#123; /* 是回文 */ &#125;    // ==========================================    // 6. 修改与删除    // ==========================================    string S = &quot;hello world&quot;;    // 插入: insert(下标, 字符串)    S.insert(5, &quot; my&quot;); // &quot;hello my world&quot;        // 删除: erase(开始下标, 删除长度)    S.erase(5, 3); // 删除 &quot; my&quot;        // 替换: replace(开始下标, 长度, 替换成的内容)    S.replace(6, 5, &quot;C++&quot;); // 把 world 换成 C++    // ==========================================    // 7. 字符判断与大小写转换    // ==========================================    char c = &#x27;A&#x27;;        // 判断类 (返回 true/false)    if (isdigit(c)) &#123;&#125; // 是数字吗 &#x27;0&#x27;-&#x27;9&#x27;    if (isalpha(c)) &#123;&#125; // 是字母吗 &#x27;a&#x27;-&#x27;z&#x27; 或 &#x27;A&#x27;-&#x27;Z&#x27;    if (islower(c)) &#123;&#125; // 是小写吗    if (isupper(c)) &#123;&#125; // 是大写吗        // 转换类 (注意: 只能转单个字符)    char low = tolower(&#x27;A&#x27;); // &#x27;a&#x27;    char up = toupper(&#x27;b&#x27;);  // &#x27;B&#x27;        // 把整个字符串转小写    for(int i=0; i&lt;s.size(); i++) s[i] = tolower(s[i]);    // ==========================================    // 8. 字典序 (Lexicographical Order)    // ==========================================    // 字符串可以直接比较大小，比的是字典序    // &quot;abc&quot; &lt; &quot;abd&quot; (true)    // &quot;abc&quot; &lt; &quot;abcd&quot; (true, 短的在前)    // &quot;10&quot; &lt; &quot;2&quot; (true! 字符 &#x27;1&#x27; &lt; &#x27;2&#x27;) -&gt; 这是一个经典坑点！    // 只有转换成数字比较才是数值大小，直接比 string 是按字符ASCII码比。    return 0;&#125;
string s = &quot;0123456789&quot;;// 1. 最常用的写法：指定起点和长度// 从下标 2 开始，切 3 个字符string s1 = s.substr(2, 3); // 结果: &quot;234&quot; (下标2, 3, 4) -&gt; 没错，是 &quot;234&quot;，不是 &quot;23&quot;！// 2. 只填起点：切到末尾// 从下标 5 开始，一直切到最后string s2 = s.substr(5); // 结果: &quot;56789&quot;// 3. 常见的坑 (易错点!)// 很多人以为 s.substr(2, 5) 是从下标2切到下标5... 错！！！string s3 = s.substr(2, 5);// 结果: &quot;23456&quot; (从下标2开始，往后数5个字符)
#include &lt;bits/stdc++.h&gt;using namespace std;int main() &#123;    string s = &quot;Hello World&quot;;    // ==========================================    // 1. 信息与状态 (基础必知)    // ==========================================    s.size();       // 获取长度 (常用)    s.length();     // 和 size() 一模一样    s.empty();      // 判断是否为空 (true 为空)    s.clear();      // 清空字符串，变成 &quot;&quot;    s.front();      // 获取第一个字符，等价于 s[0]    s.back();       // 获取最后一个字符，等价于 s[s.size()-1]    // ==========================================    // 2. 构造与初始化 (快速造串)    // ==========================================    string s1(5, &#x27;A&#x27;);  // 生成 &quot;AAAAA&quot; (想要几个重复字符时超好用！)    string s2(s, 0, 3); // 拷贝 s 的从下标0开始的3个字符 -&gt; &quot;Hel&quot; (类似 substr 的构造版)    // ==========================================    // 3. 查找类 API (侦探功能)    // ==========================================    // A. 从左往右找    // 返回第一次出现的位置下标，找不到返回 string::npos    int pos1 = s.find(&quot;World&quot;);         // B. 从右往左找 (找最后一个)    // 比如找文件名后缀 &quot;test.cpp.bak&quot; 里的最后一个 &#x27;.&#x27;    int pos2 = s.rfind(&#x27;.&#x27;);     // C. 查找“任意一个”字符 (高级用法!)    // 查找 s 中第一个属于 &quot;aeiou&quot; 的字符的位置 (找元音)    int pos3 = s.find_first_of(&quot;aeiou&quot;);         // D. 查找“第一个不属于”的字符 (高级用法!)    // 查找 s 中第一个不是数字的字符    int pos4 = s.find_first_not_of(&quot;0123456789&quot;);    // ==========================================    // 4. 修改类 API (除了 substr 还有这些!)    // ==========================================    // A. 截取 (回顾)    // s.substr(pos, len);  // 返回新串，原串 s 不变！    // B. 插入    // s.insert(pos, &quot;内容&quot;);    s.insert(5, &quot; My&quot;);     // 在下标5插入 -&gt; &quot;Hello My World&quot;    // C. 删除 (慎用，会改变原串下标)    // s.erase(pos, len);   // 从 pos 开始删 len 个    s.erase(5, 3);          // 删除 3 个字符    // D. 替换    // s.replace(pos, len, &quot;新内容&quot;);     // 把下标6开始的5个字符(World)换成&quot;Cpp&quot;    s.replace(6, 5, &quot;Cpp&quot;); // -&gt; &quot;Hello Cpp&quot;    // E. 拼接    s += &quot;!!!&quot;;             // 最常用的写法    s.append(&quot; 123&quot;);       // 等同于 +=    s.push_back(&#x27;A&#x27;);       // 在末尾加一个【字符】(只能加字符)    s.pop_back();           // 删掉末尾一个字符    // ==========================================    // 5. 转换类 (数字 &lt;-&gt; 字符串)    // ==========================================    // String -&gt; Int/Long Long    int n = stoi(&quot;123&quot;);         // 字符串转 int    long long ll = stoll(&quot;1234567890123&quot;); // 字符串转 long long    double d = stod(&quot;3.14&quot;);     // 字符串转 double    // Int/Long Long -&gt; String    string ns = to_string(123);  // 任意数字转字符串    // ==========================================    // 6. 秘密武器：stringstream (空格切割神器)    // ==========================================    // 场景：题目给你一行句子 &quot;I love ACM algorithm&quot;，让你把单词一个个取出来    // 不要自己写 for 循环判断空格！用这个！        string line = &quot;I love ACM algorithm&quot;;    stringstream ss(line); // 把字符串塞进流里    string word;    while (ss &gt;&gt; word) &#123;   // 像 cin 一样一个个读，自动跳过空格        cout &lt;&lt; word &lt;&lt; endl;         // 第一次输出 I，第二次 love，第三次 ACM...    &#125;    // ==========================================    // 7. 配合 algorithm 库的常用操作    // ==========================================    // 排序    sort(s.begin(), s.end());         // 反转    reverse(s.begin(), s.end());         // 计数 (数数里面有几个 &#x27;A&#x27;)    int cnt = count(s.begin(), s.end(), &#x27;A&#x27;);         // 去重 (类似 vector，先排序再 unique)    auto end_unique = unique(s.begin(), s.end());    s.erase(end_unique, s.end()); // 必须配合 erase 才能真删掉    // 大小写转换 (暴力转全小写)    // transform(开始, 结束, 目标开始, ::tolower);    transform(s.begin(), s.end(), s.begin(), ::tolower);    return 0;&#125;
 冰茶鸡鸡
int fa[N]; // 存每个人的“爸爸”// 初始化: 每个人是自己的爸爸void init(int n) &#123;    for (int i = 1; i &lt;= n; i++) fa[i] = i;&#125;// 查找 (带路径压缩): 找祖宗int find(int x) &#123;    if (x == fa[x]) return x;    return fa[x] = find(fa[x]); // 路径压缩，下次找更快&#125;// 合并: 把 x 和 y 所在的家族合并void join(int x, int y) &#123;    int rootX = find(x);    int rootY = find(y);    if (rootX != rootY) &#123;        fa[rootX] = rootY; // 让 X 的祖宗认 Y 的祖宗为爸爸    &#125;&#125;// 查询: 两个点是否连通bool isConnected(int x, int y) &#123;    return find(x) == find(y);&#125;
 图论

多人去同一个地方（多起点 -&gt; 单终点）

题目特征：题目给了 NNN 个人（或者 NNN 个城市），问：“这 NNN 个人都要去同一个目的地 TTT 集合，请问谁离目的地最远/最近？或者所有人走的总路程是多少？”
为什么不能直接做？如果你按照正常的思维：每个人跑一次 Dijkstra，就要跑 NNN 次。时间复杂度爆炸，绝对超时 (TLE)。反向建边怎么破？
逻辑： “AAA 走到 BBB” 等价于 “在反向图中，从 BBB 走到 AAA”。
操作：建反图（所有箭头掉头）。只从目的地 TTT 出发，在反向图上跑一次 Dijkstra。跑出来的 dist[i]，意思就是 “原图中 iii 号点走到目的地 TTT 的最短距离”。
收益： 跑 NNN 次变成跑 1 次，秒杀。


有去有回（往返最短路）

题目特征：题目问：“邮递员从起点 111 送信到 NNN 个地方，送完还得回到起点 111，求最小的总路程。”或者简单的问：“求 AAA 到 BBB 再回到 AAA 的最短路径。”
反向建边怎么破？去程： 在正向图上跑一次 Dijkstra（起点 111），得到 dist_to[i]（从家去别处的距离）。
回程： 在反向图上再跑一次 Dijkstra（还是从起点 111 开始跑！），得到 dist_back[i]。
注意：反向图上从 1 出发到 i 的距离，其实就是原图里 i 回到 1 的距离。
答案： 第 iii 个地点的往返总路程 = dist_to[i] + dist_back[i]。



 小鸡鸡桥

断环为链 (Breaking the Circular Array)

什么时候用？题目特征： 题目说“大家围成一个圈坐着”、“项链上的珠子”、“环形跑道”。
难点： 数组是直的，环是圆的，处理“下标越界”或者“跨过终点回到起点”非常麻烦，容易写全是 Bug。
神操作：复制一遍！ 把原数组 a[1…n] 复制一份接在后面，变成 a[1…2n]。比如原数组是 [1, 2, 3]，新数组变成 [1, 2, 3, 1, 2, 3]。
效果： 环上任意一段长度为 NNN 的路径，现在都在这个 2N2N2N 的直数组里变成了连续的一段。
做法： 以后再也不用 % n 取模了，直接在 1 到 2n 的范围里做滑动窗口或者前缀和。



#include &lt;bits/stdc++.h&gt;using namespace std;const int N = 200005; // 注意！因为要复制一遍，数组大小要开 2*N 以上！int a[N]; // 原数组int s[N]; // 前缀和数组 (如果题目需要求区间和)int main() &#123;    int n;    cin &gt;&gt; n;    // ==========================================    // 核心操作：读入 + 复制 + (可选)前缀和    // ==========================================    for (int i = 1; i &lt;= n; i++) &#123;        cin &gt;&gt; a[i];       // 读入第 i 个数        a[i + n] = a[i];   // 【断环为链】把第 i 个数复制到 i+n 的位置    &#125;    // 现在的数组长这样 (假设 n=3, 数据是 1 2 3):    // 下标: 1  2  3  4  5  6    // 数据: 1  2  3  1  2  3    // 你可以直接在 1 到 2*n 的范围内跑循环，完全不用取模！    // (可选) 计算前缀和: 用于快速求区间和    for (int i = 1; i &lt;= 2 * n; i++) &#123;        s[i] = s[i - 1] + a[i];    &#125;    // ==========================================    // 典型用法：枚举长度为 n 的所有区间    // ==========================================    // 比如：找一个长度为 n 的区间，使得区间和最大    int max_sum = -1e9;        for (int i = 1; i &lt;= n; i++) &#123;        // 当前区间是: [i, i + n - 1]        // 这是一个长度为 n 的窗口，涵盖了环上的一种情况                // 利用前缀和快速计算这段的和        // sum = s[右端点] - s[左端点 - 1]        int current_sum = s[i + n - 1] - s[i - 1];                max_sum = max(max_sum, current_sum);    &#125;    cout &lt;&lt; max_sum &lt;&lt; endl;    return 0;&#125;
 速度查询
// 1. 数二进制里有几个 1 (popcount)int x = 13; // 二进制 1101int cnt = __builtin_popcount(x); // 结果 3// 注意：如果是 long long，要用 __builtin_popcountll(x)// 2. 数二进制末尾有几个 0 (CTZ - Count Trailing Zeros)// 比如 8 (1000)，末尾有 3 个 0int z = __builtin_ctz(8); // 结果 3// 常用技巧：x 的 lowest set bit (最低位的1) 对应的值是 1 &lt;&lt; __builtin_ctz(x)// 3. 数二进制前面有几个 0 (CLZ - Count Leading Zeros)// 常用技巧：快速算 log2(x) (向下取整)// 因为 int 是 32 位，所以 log2(x) = 31 - __builtin_clz(x)int lg = 31 - __builtin_clz(16); // 结果 4
int tree[N]; // 树状数组int n; // 元素个数// 1. lowbit (取最低位的1)int lowbit(int x) &#123; return x &amp; -x; &#125;// 2. 单点修改：给第 x 个数加上 v (注意是加，不是变成)void add(int x, int v) &#123;    for (; x &lt;= n; x += lowbit(x)) tree[x] += v;&#125;// 3. 前缀查询：求 1 到 x 的和int query(int x) &#123;    int sum = 0;    for (; x &gt; 0; x -= lowbit(x)) sum += tree[x];    return sum;&#125;// 求区间 [L, R] 的和: query(R) - query(L - 1)


点修改 + 区间求和 (PURQ)

这是最基础、最可能出现的类型。操作： 设数组 AAA。A[x] += v求 ∑i=LRA[i]\sum_{i=L}^{R} A[i]∑i=LR​A[i]
套用公式：修改： 调用 add(x, v)。查询： 调用 query® - query(L - 1)。



套路二：区间修改 + 求单点值 (RUPQ)这是最巧妙的类型，用到了差分思想。

核心： 设 DDD 是 AAA 的差分数组 (D[i]=A[i]−A[i−1]D[i] = A[i] - A[i-1]D[i]=A[i]−A[i−1])。对 AAA 数组求前缀和 ∑i=1xD[i]\sum_{i=1}^{x} D[i]∑i=1x​D[i] 就能还原 A[x]A[x]A[x] 的值。
操作：给 AAA 数组的区间 [L,R][L, R][L,R] 上的所有数都加上 vvv。求 A[x]A[x]A[x] 的值。
套用公式：修改： 对 DDD 数组进行单点修改：add(L, v); // L 位置增加 vadd(R + 1, -v); // R+1 位置减少 v (抵消后续影响)
查询 A[x]A[x]A[x] 的值：对 DDD 数组求前缀和：A[x] = query(x);

gcd相关 gcd构造性质：知道 矩阵
核心模型:左右互质性质：相邻自然数必然互质。余数非零性质：跨越边界的质数选择 思维误区 (Bug):上下互质性质：质数步长 + 辗转相除法。元素唯一性质：带余除法的唯一性。数学表达： 在 n 较小（如 2500 以内）时，大于 n 的第一个质数 PPP 与 n 的距离非常近，最大差值不超过 34。 修正逻辑 (Patch): 关键代码:
const int N = 1e7 + 10; // 10^7 级别int primes[N], cnt; // primes存质数，cnt存质数个数bool st[N]; // st[i]为true表示i是合数(被筛掉了)，false表示是质数void get_primes(int n)&#123; for (int i = 2; i &lt;= n; i++) &#123; // 如果没有被标记过，说明 i 是质数，加入 primes 列表 if (!st[i]) primes[cnt++] = i; // 核心循环：用当前的质数 primes[j] 去筛合数 for (int j = 0; primes[j] &lt;= n / i; j++) &#123; // primes[j] * i &lt;= n // 1. 标记 primes[j] * i 为合数 st[primes[j] * i] = true; // 2. 【最关键的一行】 // 如果 i 能被 primes[j] 整除，说明 primes[j] 已经是 i 的最小质因子了 // 那么 primes[j] 也一定是 primes[j] * i 的最小质因子 // 我们必须立刻停止，避免重复筛 if (i % primes[j] == 0) break; &#125; &#125;&#125;void solve()&#123; int n; cin &gt;&gt; n; // n=2500; get_primes(n * n + 40 * n); vi zhi; for (int i = 0; i &lt; n * n + 40 * n; i++) &#123; if (primes[i]) zhi.push_back(primes[i]); &#125; vector&lt;vi&gt; ans(n + 1, vi(n + 1)); int fk=*upper_bound(all(zhi),n); for (int i = 1; i &lt;= n; i++) &#123; for (int j = 1; j &lt;= n; j++) &#123; if(i==1) &#123; ans[i][j]=j; &#125; else &#123; ans[i][j]=j+fk*(i-1); &#125; &#125; &#125; for (int i = 1; i &lt;= n; i++) &#123; for (int j = 1; j &lt;= n; j++) &#123; cout &lt;&lt; ans[i][j] &lt;&lt; &#x27; &#x27;; &#125; cout &lt;&lt; &#x27;\n&#x27;; &#125;&#125;

